   1 | <!DOCTYPE html>
   2 | <html lang="zh-Hant">
   3 | <head>
   4 |     <meta charset="UTF-8">
   5 |     <meta name="viewport" content="width=device-width, initial-scale=1.0">
   6 |     <meta http-equiv="Cache-Control" content="no-cache, no-store, must-revalidate">
   7 |     <meta http-equiv="Pragma" content="no-cache">
   8 |     <meta http-equiv="Expires" content="0">
   9 |     <title>VCC PRE 廣播主控室操作員矩陣首頁系統 v0.5</title>
  10 |     <style>
  11 |         body {
  12 |             margin: 0;
  13 |             padding: 0;
  14 |             background-color: #090d16;
  15 |             font-family: "Microsoft JhengHei", "微軟正黑體", Arial, sans-serif;
  16 |         }
  17 | 
  18 |         /* 獨立沙盒包裝層 */
  19 |         .vcc-pre-system-sandbox-wrapper {
  20 |             --sidebar-width: 260px;
  21 |             --primary-color: #38bdf8;
  22 |             --bg-dark: #090d16;
  23 |             --bg-panel: #111827;
  24 |             --success: #10b981;
  25 |             --warning: #f59e0b;
  26 |             --danger: #ef4444;
  27 |             --on-air: #22c55e;
  28 | 
  29 |             display: flex !important;
  30 |             width: 100% !important;
  31 |             height: 100vh !important;
  32 |             min-height: 780px;
  33 |             background-color: var(--bg-dark);
  34 |             color: #f1f5f9;
  35 |             box-sizing: border-box;
  36 |             overflow: hidden !important;
  37 |             position: relative;
  38 |         }
  39 | 
  40 |         .vcc-pre-system-sandbox-wrapper *,
  41 |         .vcc-pre-system-sandbox-wrapper *:before,
  42 |         .vcc-pre-system-sandbox-wrapper *:after {
  43 |             box-sizing: border-box;
  44 |         }
  45 | 
  46 |         /* 左側常駐工作列 */
  47 |         .sidebar {
  48 |             width: var(--sidebar-width);
  49 |             min-width: var(--sidebar-width);
  50 |             background-color: var(--bg-panel);
  51 |             border-right: 1px solid #1f2937;
  52 |             display: flex;
  53 |             flex-direction: column;
  54 |             justify-content: space-between;
  55 |             height: 100%;
  56 |             z-index: 10;
  57 |         }
  58 |         .sidebar-header {
  59 |             padding: 24px 20px;
  60 |             text-align: center;
  61 |             font-size: 16px;
  62 |             font-weight: bold;
  63 |             letter-spacing: 1px;
  64 |             color: var(--primary-color);
  65 |             border-bottom: 1px solid #1f2937;
  66 |             background: linear-gradient(180deg, rgba(56,189,248,0.05) 0%, rgba(0,0,0,0) 100%);
  67 |         }
  68 |         .sidebar-menu { flex: 1; padding: 20px 0; }
  69 |         .menu-item {
  70 |             padding: 15px 20px; color: #9ca3af; cursor: pointer; font-size: 14px; display: flex; align-items: center; gap: 12px; transition: all 0.2s;
  71 |         }
  72 |         .menu-item:hover { background-color: rgba(56, 189, 248, 0.04); color: #fff; }
  73 |         .menu-item.active {
  74 |             background-color: rgba(56, 189, 248, 0.08); color: var(--primary-color); border-left: 4px solid var(--primary-color); font-weight: bold;
  75 |         }
  76 |         .sidebar-footer { padding: 20px; font-size: 11px; color: #4b5563; text-align: center; border-top: 1px solid #1f2937; line-height: 1.6; }
  77 | 
  78 |         /* 右側核心工作區 */
  79 |         .main-content { flex: 1; padding: 25px; overflow-y: auto !important; height: 100%; background-color: var(--bg-dark); }
  80 |         .page { display: none; }
  81 |         .page.active { display: block; }
  82 | 
  83 |         /* 模組容器 */
  84 |         .panel-box {
  85 |             background-color: var(--bg-panel); padding: 22px; border-radius: 8px; box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.7); margin-bottom: 20px; border: 1px solid #1f2937;
  86 |         }
  87 |         .panel-header-box {
  88 |             display: flex; justify-content: space-between; align-items: center; margin-bottom: 18px; border-bottom: 1px solid #1f2937; padding-bottom: 10px;
  89 |         }
  90 |         .panel-title { font-size: 14px; color: var(--primary-color); font-weight: bold; letter-spacing: 0.5px; text-transform: uppercase; }
  91 | 
  92 |         /* 廣播主控專用：頂部極致三欄網格佈局 (首頁專用) */
  93 |         .mcr-operator-grid {
  94 |             display: grid;
  95 |             grid-template-columns: 1.2fr 1fr;
  96 |             gap: 20px;
  97 |             margin-bottom: 20px;
  98 |         }
  99 |         @media(max-width: 1200px) { .mcr-operator-grid { grid-template-columns: 1fr; } }
 100 | 
 101 |         /* MCR On-Air 監測監視器樣式 */
 102 |         .mcr-monitor-card {
 103 |             background: linear-gradient(135deg, #0b1519 0%, #111827 100%);
 104 |             border: 2px solid #10b981;
 105 |             border-radius: 8px;
 106 |             padding: 20px;
 107 |             position: relative;
 108 |             box-shadow: 0 0 20px rgba(16, 185, 129, 0.1);
 109 |         }
 110 |         .mcr-monitor-card.no-active {
 111 |             border-color: #374151;
 112 |             box-shadow: none;
 113 |         }
 114 |         .mcr-tag-live {
 115 |             position: absolute; top: 15px; right: 20px; background-color: var(--on-air); color: #fff; padding: 3px 8px; font-size: 11px; font-weight: bold; border-radius: 4px; letter-spacing: 1px; animation: blinker 1.5s linear infinite;
 116 |         }
 117 |         @keyframes blinker { 50% { opacity: 0.3; } }
 118 | 
 119 |         .mcr-label-sub { font-size: 12px; color: #9ca3af; text-transform: uppercase; margin-bottom: 4px; font-weight: 600; }
 120 |         .mcr-prog-title { font-size: 26px; font-weight: 900; color: #ffffff; margin: 5px 0 15px 0; letter-spacing: 0.5px; text-shadow: 0 2px 4px rgba(0,0,0,0.5); }
 121 |         .mcr-prog-countdown { font-family: 'Courier New', Courier, monospace; font-size: 24px; color: var(--warning); font-weight: bold; }
 122 |         .mcr-next-bar { background-color: rgba(255,255,255,0.03); border-left: 3px solid var(--primary-color); padding: 10px 15px; margin-top: 15px; border-radius: 0 4px 4px 0; }
 123 | 
 124 |         /* Traffic 摘要狀態卡片 */
 125 |         .traffic-summary-card {
 126 |             background: #111827; border: 1px solid #1f2937; border-radius: 8px; padding: 20px; display: grid; grid-template-columns: 1fr 1fr; gap: 15px;
 127 |         }
 128 |         .traffic-stat-block {
 129 |             background: #0b0f19; padding: 12px; border-radius: 6px; border-top: 3px solid #4b5563; text-align: center;
 130 |         }
 131 |         .traffic-stat-block.alert-active { border-top-color: var(--danger); background: rgba(239, 68, 68, 0.03); }
 132 |         .traffic-stat-num { font-family: monospace; font-size: 24px; font-weight: bold; color: #fff; margin-top: 4px; }
 133 | 
 134 |         /* 雙欄排版（用於行事曆與表單對齊） */
 135 |         .grid-layout-2col { display: grid; grid-template-columns: 340px 1fr; gap: 20px; margin-bottom: 20px; }
 136 |         @media(max-width: 1024px) { .grid-layout-2col { grid-template-columns: 1fr; } }
 137 | 
 138 |         /* --- NATIVE GUI CALENDAR STYLE --- */
 139 |         .gui-calendar-card { background: #090d16; border: 1px solid #1f2937; border-radius: 6px; padding: 12px; }
 140 |         .calendar-nav-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }
 141 |         .calendar-nav-header span { font-size: 14px; font-weight: bold; color: #fff; }
 142 |         .calendar-nav-btn { background: #1f2937; color: #fff; padding: 4px 8px; font-size: 12px; border-radius: 4px; cursor: pointer; }
 143 |         .calendar-nav-btn:hover { background: var(--primary-color); color: #090d16; }
 144 |         .calendar-grid-head { display: grid; grid-template-columns: repeat(7, 1fr); text-align: center; font-size: 11px; color: #4b5563; margin-bottom: 6px; font-weight: bold; }
 145 |         .calendar-grid-body { display: grid; grid-template-columns: repeat(7, 1fr); gap: 4px; text-align: center; }
 146 |         .calendar-day-cell {
 147 |             aspect-ratio: 1; background: #111827; border-radius: 6px; display: flex; flex-direction: column; justify-content: center; align-items: center; font-size: 13px; font-family: monospace; cursor: pointer; position: relative; transition: all 0.15s; border: 1px solid transparent; color: #cbd5e1; gap:1px;
 148 |         }
 149 |         .calendar-day-cell:hover { border-color: var(--primary-color); background: rgba(56, 189, 248, 0.06); }
 150 |         .calendar-day-cell.empty { background: transparent; cursor: default; border: none; }
 151 |         .calendar-day-cell.selected { background: var(--primary-color) !important; color: #090d16 !important; font-weight: bold; border-color: var(--primary-color) !important; }
 152 |         .calendar-day-cell.today { border: 1px solid var(--success); }
 153 |         .calendar-day-cell.selected.today { border-color: var(--primary-color) !important; }
 154 |         .calendar-prog-count { font-size:9px; color:#64748b; font-weight:normal; font-family:sans-serif; }
 155 |         .calendar-day-cell.selected .calendar-prog-count { color:#090d16; opacity:0.7; }
 156 |         .calendar-day-cell.has-progs { border-bottom:2px solid #a855f7; }
 157 | 
 158 |         /* 表單與控制元件 */
 159 |         .input-form { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
 160 |         .input-group { display: flex; flex-direction: column; }
 161 |         .input-group.full-width { grid-column: span 2; }
 162 |         .input-group label { font-size: 12px; color: #9ca3af; margin-bottom: 4px; }
 163 |         .input-group input, .input-group select, .input-group textarea {
 164 |             background-color: #090d16; border: 1px solid #374151; color: #fff; padding: 8px 10px; border-radius: 4px; font-size: 13px; outline: none;
 165 |         }
 166 |         .input-group input:focus, .input-group select:focus, .input-group textarea:focus { border-color: var(--primary-color); }
 167 |         /* 窄螢幕響應式: 768px 以下調整表單成單欄 */
 168 |         @media (max-width: 768px) {
 169 |             .input-form { grid-template-columns: 1fr; }
 170 |             .input-form .input-group input[type="text"] { font-size: 16px; padding: 10px 8px; }
 171 |             .input-group.full-width { grid-column: span 1; }
 172 |         }
 173 | 
 174 |         /* 頂部全局控制列 */
 175 |         .global-filter-bar {
 176 |             background: #111827; padding: 12px 20px; border-radius: 6px; margin-bottom: 20px; display: flex; align-items: center; gap: 15px; border: 1px solid #1f2937;
 177 |         }
 178 |         .global-filter-bar input[type="date"] { background: #090d16; border: 1px solid #374151; color: #fff; padding: 6px 10px; border-radius: 4px; }
 179 | 
 180 |         /* 按鈕樣式 */
 181 |         .btn-zone { display: flex; gap: 10px; margin-top: 10px; }
 182 |         button { padding: 9px 14px; font-size: 12px; font-weight: bold; border-radius: 4px; cursor: pointer; border: none; transition: all 0.2s; }
 183 |         .btn-add { background-color: #0284c7; color: white; }
 184 |         .btn-update { background-color: var(--warning); color: #090d16; }
 185 |         .btn-start { background-color: var(--success); color: white; font-size: 13px; padding: 10px 20px; box-shadow: 0 0 10px rgba(16,185,129,0.2); }
 186 |         .btn-sync { background-color: #374151; color: white; }
 187 |         .btn-cancel { background-color: #4b5563; color: white; }
 188 |         .btn-danger-action { background-color: rgba(239, 68, 68, 0.15); color: #f87171; border: 1px solid var(--danger); }
 189 | 
 190 |         .btn-ctrl-group { display: flex; gap: 6px; }
 191 |         .btn-ctrl { padding: 6px 12px; font-size: 11px; font-weight: bold; border-radius: 4px; color: white; }
 192 |         .btn-import-ui { background-color: #374151; }
 193 |         .btn-export-ui { background-color: #0284c7; }
 194 |         .btn-clear-ui { background-color: rgba(239, 68, 68, 0.15); color: #f87171; border: 1px solid #dc2626; }
 195 | 
 196 |         /* HUD 全域看板 */
 197 |         .status-panel {
 198 |             background-color: var(--bg-panel); padding: 15px 20px; border-radius: 8px; margin-bottom: 20px; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; border-left: 5px solid var(--primary-color); border-top: 1px solid #1f2937; border-right: 1px solid #1f2937; border-bottom: 1px solid #1f2937;
 199 |         }
 200 |         .status-item { font-size: 14px; margin: 2px 0; color: #9ca3af; }
 201 |         .status-item span { font-weight: bold; color: var(--warning); }
 202 |         .sync-badge { padding: 3px 7px; border-radius: 4px; font-size: 11px; font-weight: bold; display: inline-block; }
 203 |         .sync-success { background-color: rgba(16, 185, 129, 0.15); color: #34d399; border: 1px solid var(--success); }
 204 |         .sync-loading { background-color: rgba(59, 130, 246, 0.15); color: #60a5fa; border: 1px solid #3b82f6; }
 205 |         #clock { font-family: 'Courier New', Courier, monospace; font-size: 48px; color: var(--success); font-weight: bold; text-shadow: 0 0 16px rgba(16, 185, 129, 0.35); letter-spacing: 2px; }
 206 | 
 207 |         /* 系統表格 */
 208 |         .vcc-pre-table { width: 100%; border-collapse: collapse; font-size: 13px; background-color: var(--bg-panel); border-radius: 6px; overflow: hidden; }
 209 |         .vcc-pre-table th { background-color: #090d16; color: #9ca3af; text-align: left; padding: 12px 14px; border-bottom: 2px solid #1f2937; text-transform: uppercase; font-size: 12px; letter-spacing: 0.5px; }
 210 |         .vcc-pre-table td { padding: 12px 14px; border-bottom: 1px solid #1f2937; color: #e5e7eb; }
 211 |         .status-badge { padding: 2px 6px; border-radius: 4px; font-size: 11px; font-weight: bold; }
 212 |         .badge-sched { background-color: #1f2937; color: #cbd5e1; }
 213 |         .badge-periodic { background-color: rgba(168, 85, 247, 0.15); color: #c084fc; border: 1px solid #a855f7; }
 214 | 
 215 |         .btn-action { padding: 4px 8px; font-size: 11px; margin-right: 4px; border-radius: 4px; cursor: pointer; color: white; border: none;}
 216 |         .btn-action-edit { background-color: #d97706; }
 217 |         .btn-action-copy { background-color: #0891b2; }
 218 |         .btn-action-del { background-color: #dc2626; }
 219 | 
 220 |         /* 動態聚焦行 */
 221 |         .row-imminent { color: var(--danger) !important; background-color: rgba(239, 68, 68, 0.1) !important; font-weight: bold; border-left: 5px solid var(--danger) !important; }
 222 |         .row-imminent td { color: var(--danger) !important; }
 223 |         .row-future { color: var(--warning) !important; }
 224 |         .row-future td { color: var(--warning) !important; }
 225 |         .row-dimmed { color: #64748b !important; }
 226 |         .row-dimmed td { color: #64748b !important; }
 227 |         .row-trigger-active { background-color: var(--danger) !important; color: #ffffff !important; font-weight: bold; animation: pulse 0.4s infinite alternate; }
 228 |         .row-trigger-active td { color: #ffffff !important; }
 229 |         @keyframes pulse { 0% { background-color: var(--danger); } 100% { background-color: #b91c1c; } }
 230 |         /* 矩陣捲動容器 */
 231 |         .matrix-scroll-wrap { overflow-y: auto; border: 1px solid #1f2937; border-radius: 6px; }
 232 |         .matrix-scroll-wrap::-webkit-scrollbar { width: 6px; }
 233 |         .matrix-scroll-wrap::-webkit-scrollbar-track { background: #090d16; }
 234 |         .matrix-scroll-wrap::-webkit-scrollbar-thumb { background: #374151; border-radius: 3px; }
 235 | 
 236 |         /* 除錯終端 */
 237 |         .console-terminal {
 238 |             background-color: #030712; border: 1px solid #1f2937; font-family: 'Courier New', Courier, monospace; font-size: 12px; color: #34d399; padding: 12px; border-radius: 6px; height: 130px; overflow-y: auto; line-height: 1.4; margin-top: 5px;
 239 |         }
 240 |         .console-line { margin-bottom: 4px; }
 241 |         .console-time { color: #4b5563; margin-right: 8px; }
 242 | 
 243 |         /* Timeline GUI 時間軸 */
 244 |         .timeline-panel { display:flex; gap:8px; padding:8px 12px; background:#111827; border:1px solid #1f2937; border-radius:6px; margin-bottom:12px; align-items:stretch; }
 245 |         .timeline-label { font-size:11px; color:#64748b; white-space:nowrap; font-family:monospace; min-width:90px; padding-top:20px; }
 246 |         .timeline-tracks-wrap { flex:1; position:relative; overflow-x:hidden; background:#090d16; border-radius:4px; min-height:0; }
 247 |         .timeline-track { display:flex; align-items:center; height:28px; border-bottom:1px solid rgba(31,41,55,0.4); position:relative; }
 248 |         .timeline-track:last-child { border-bottom:none; }
 249 |         .timeline-track-label { width:100px; min-width:100px; font-size:10px; color:#9ca3af; padding:0 6px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; position:relative; z-index:2; }
 250 |         .timeline-track-bar { flex:1; position:relative; height:100%; }
 251 |         .timeline-prog-block { position:absolute; top:3px; height:20px; border-radius:3px; opacity:0.55; cursor:pointer; z-index:3; border:1px solid rgba(255,255,255,0.08); transition:opacity 0.15s; }
 252 |         .timeline-prog-block:hover { opacity:0.85; }
 253 |         .timeline-cue-tick { position:absolute; top:3px; width:2px; height:20px; border-radius:1px; opacity:0.6; cursor:pointer; z-index:4; }
 254 |         .timeline-cue-tick:hover { opacity:1; transform:scaleX(2); z-index:5; }
 255 |         .timeline-now-marker { position:absolute; top:0; width:3px; height:100%; background:var(--danger); z-index:10; border-radius:1px; box-shadow:0 0 8px var(--danger); transition:left 0.4s linear; pointer-events:none; }
 256 |         .timeline-now-label { position:absolute; top:-18px; font-size:10px; font-weight:bold; color:var(--danger); transform:translateX(-50%); white-space:nowrap; z-index:11; pointer-events:none; }
 257 |         .timeline-ruler { display:flex; height:18px; border-bottom:1px solid #1f2937; position:relative; }
 258 |         .timeline-ruler-label { position:absolute; font-size:9px; color:#4b5563; transform:translateX(-50%); top:2px; }
 259 | 
 260 |         /* Week at a Glance */
 261 |         .week-grid { display:grid; grid-template-columns:repeat(7,1fr); gap:1px; background:#1f2937; border-radius:6px; overflow:hidden; }
 262 |         .week-day-header { background:#111827; padding:8px 4px; text-align:center; font-size:11px; color:#9ca3af; font-weight:bold; border-bottom:2px solid #1f2937; }
 263 |         .week-day-header span { display:block; font-size:18px; color:#fff; font-weight:bold; margin-top:2px; }
 264 |         .week-day-header.today { color:#10b981; } .week-day-header.today span { color:#10b981; }
 265 |         .week-day-cell { background:#090d16; padding:4px; min-height:60px; font-size:10px; vertical-align:top; }
 266 |         .week-prog-block { padding:3px 4px; margin-bottom:2px; border-radius:3px; border-left:3px solid; cursor:pointer; line-height:1.3; }
 267 |         .week-prog-block:hover { filter:brightness(1.3); }
 268 |         #rundownTableBody tr { cursor:pointer; }
 269 |         #rundownTableBody tr:hover { background:rgba(56,189,248,0.03); }
 270 |         .week-prog-block .wp-time { color:#94a3b8; font-family:monospace; font-size:9px; }
 271 |         .week-prog-block .wp-name { color:#e2e8f0; font-weight:bold; font-size:10px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
 272 |         .week-prog-block .wp-tags { display:flex; gap:2px; flex-wrap:wrap; margin-top:1px; }
 273 | 
 274 |         /* Tag & Color Label */
 275 |         .tag-badge { display:inline-block; padding:1px 5px; border-radius:3px; font-size:9px; font-weight:bold; margin:1px 2px 1px 0; }
 276 | 
 277 |         .clr-picker { display:flex; gap:4px; flex-wrap:wrap; margin-top:4px; }
 278 |         .clr-opt { width:24px; height:24px; border-radius:50%; cursor:pointer; border:2px solid transparent; transition:all 0.15s; }
 279 |         .clr-opt:hover { transform:scale(1.2); }
 280 |         .clr-opt.active { border-color:#fff !important; box-shadow:0 0 6px rgba(255,255,255,0.4); }
 281 |         .tag-input-area { display:flex; gap:4px; flex-wrap:wrap; align-items:center; }
 282 |         .tag-input-area input { flex:1; background:#090d16; border:1px solid #374151; color:#fff; padding:5px 8px; border-radius:4px; font-size:12px; outline:none; }
 283 |         .tag-input-area input:focus { border-color:#38bdf8; }
 284 |         .tag-list { display:flex; gap:3px; flex-wrap:wrap; margin-top:4px; }
 285 | 
 286 |         /* 節目 Color Code */
 287 |         .prog-color-0 { --prog-color: #ef4444; } .prog-color-1 { --prog-color: #f59e0b; }
 288 |         .prog-color-2 { --prog-color: #10b981; } .prog-color-3 { --prog-color: #3b82f6; }
 289 |         .prog-color-4 { --prog-color: #8b5cf6; } .prog-color-5 { --prog-color: #ec4899; }
 290 |         .prog-color-6 { --prog-color: #06b6d4; } .prog-color-7 { --prog-color: #f97316; }
 291 |         .prog-color-dot { display:inline-block; width:10px; height:10px; border-radius:50%; margin-right:6px; vertical-align:middle; }
 292 |         .row-onair { background-color: rgba(239,68,68,0.12) !important; border-left:4px solid var(--danger) !important; animation: pulseOnAir 0.6s infinite alternate; }
 293 |         .row-nextup { background-color: rgba(245,158,11,0.08) !important; border-left:4px solid #f59e0b !important; }
 294 |         @keyframes pulseOnAir { 0% { background-color: rgba(239,68,68,0.08); } 100% { background-color: rgba(239,68,68,0.18); } }
 295 |         .matrix-row { border-left: 3px solid var(--prog-color, #374151); } /* 放在高亮 class 之後，不蓋過 .row-imminent/.row-trigger-active 的 border-left */
 296 | 
 297 |         /* Preset 節點表格樣式 */
 298 |         #presetNodesTable { width:100%; border-collapse:collapse; margin-bottom:8px; }
 299 |         #presetNodesTable th { color:#9ca3af; font-size:12px; padding:6px 4px; border-bottom:1px solid #374151; font-weight:600; text-align:left; }
 300 |         #presetNodesTable td { padding:3px 4px; border-bottom:1px solid #1f2937; }
 301 |         #presetNodesTable select,
