2411 |     function previewSound(row) {
2412 |         const sel = row.querySelector('.soundSelect');
2413 |         if (!sel) return;
2414 |         let soundId = sel.value;
2415 |         if (soundId === "silent") { writeLog("🔇 靜音模式，無提示音", 'info'); return; }
2416 |         let preset = null;
2417 |         for (let i = 0; i < soundPresets.length; i++) {
2418 |             if (soundPresets[i].id === soundId) { preset = soundPresets[i]; break; }
2419 |         }
2420 |         if (!preset) return;
2421 |         try {
2422 |             const actx = window.audioCtx || new (window.AudioContext || window.webkitAudioContext)();
2423 |             if (actx.state === 'suspended') actx.resume();
2424 |             window.audioCtx = actx;
2425 |             const repeats = preset.repeats || 1;
2426 |             const gap = preset.gap || 0;
2427 |             const dur = preset.dur || 0.3;
2428 |             let freq = preset.freq || 1000;
2429 |             let type = preset.type || 'sine';
2430 |             for (let r = 0; r < repeats; r++) {
2431 |                 (function(idx) {
2432 |                     let offset = (dur + gap) * idx;
2433 |                     setTimeout(function() {
2434 |                         const osc = actx.createOscillator();
2435 |                         const gain = actx.createGain();
2436 |                         osc.connect(gain); gain.connect(actx.destination);
2437 |                         osc.type = type;
2438 |                         osc.frequency.value = freq;
2439 |                         gain.gain.setValueAtTime(0.25, actx.currentTime);
2440 |                         osc.start(); osc.stop(actx.currentTime + dur);
2441 |                     }, offset * 1000);
2442 |                 })(r);
2443 |             }
2444 |             const info = preset.label + (repeats > 1 ? ' (' + repeats + '次)' : '');
2445 |             writeLog('🔊 Preview: ' + info);
2446 |         } catch(e) { writeLog('🔇 Preview: ' + e.message, 'error'); }
